{
    private readonly ConcurrentDictionary<string, AmazonS3EncryptionClientV2> _clients = new();

    public string AddClient(AmazonS3EncryptionClientV2 client)
    {
        var clientId = Guid.NewGuid().ToString();
        _clients[clientId] = client;
        return clientId;
    }

