using Microsoft.AspNetCore.Mvc;
using NetV3Server.Models;
using NetV3Server.Services;
using Amazon.S3;
using Amazon.KeyManagementService;
using Amazon.Extensions.S3.Encryption;
using Amazon.Extensions.S3.Encryption.Primitives;

namespace NetV3Server.Controllers;

[ApiController]
[Route("[controller]")]
public class ClientController : ControllerBase
{
    private readonly IClientCacheService _clientCacheService;

    public ClientController(IClientCacheService clientCacheService)
    {
        _clientCacheService = clientCacheService;
    }

    [HttpPost]
    public async Task<IActionResult> CreateClient([FromBody] ClientRequest request)
    {
        try
        {
            // Create KMS client (hardcoded to us-west-2 like Python)
            var kmsClient = new AmazonKeyManagementServiceClient(Amazon.RegionEndpoint.USWest2);

            // Create S3 client
            var s3Client = new AmazonS3Client(Amazon.RegionEndpoint.USWest2);

            // Create encryption materials
            var kmsKeyId = request.Config.KeyMaterial.KmsKeyId;
            var encryptionMaterials = new EncryptionMaterialsV2(kmsKeyId, KmsType.KmsContext, new Dictionary<string, string>());

            // Create encryption configuration
            var config = new AmazonS3CryptoConfigurationV2(SecurityProfile.V2AndLegacy)
            {
                StorageMode = CryptoStorageMode.ObjectMetadata
            };

            // Create S3 encryption client
            var encryptionClient = new AmazonS3EncryptionClientV2(s3Client, config, encryptionMaterials);

            // Add to cache and return client ID
            var clientId = _clientCacheService.AddClient(encryptionClient);

            return Ok(new ClientResponse { ClientId = clientId });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new S3EncryptionClientError 
            { 
                Message = $"Failed to create client: {ex.Message}" 
            });
        }
    }
}

